// V2.0: 解析查询参数 + 构建动态 WHERE (支持批量单号)
const query = $input.first().json.query || {};
const companyCode = $env.DP_COMPANY_CODE;

if (!companyCode) {
  return { json: { _error: true, message: 'DP_COMPANY_CODE not set' } };
}

const conditions = ['o.company_code = $1'];
const params = [companyCode];
let paramIdx = 2;

if (query.doc_type) {
  conditions.push(`o.doc_type = $${paramIdx++}`);
  params.push(query.doc_type);
}
if (query.business_partner) {
  conditions.push(`o.business_partner ILIKE $${paramIdx++}`);
  params.push('%' + query.business_partner + '%');
}
if (query.bp_name) {
  conditions.push(`o.bp_name ILIKE $${paramIdx++}`);
  params.push('%' + query.bp_name + '%');
}
if (query.doc_num) {
  const nums = query.doc_num.split(',').map(s => s.trim()).filter(Boolean);
  if (nums.length > 50) {
    return { json: { _error: true, message: '批量查询上限 50 个单号' } };
  }
  if (nums.length > 1) {
    conditions.push(`(o.sap_doc_num = ANY($${paramIdx}::text[]) OR o.doc_number = ANY($${paramIdx + 1}::text[]))`);
    params.push(nums, nums);
    paramIdx += 2;
  } else {
    conditions.push(`(o.sap_doc_num ILIKE $${paramIdx} OR o.doc_number ILIKE $${paramIdx})`);
    params.push('%' + nums[0] + '%');
    paramIdx++;
  }
}
if (query.warehouse) {
  conditions.push(`EXISTS(SELECT 1 FROM oms.order_lines ol2 WHERE ol2.order_id = o.id AND ol2.warehouse_code = $${paramIdx})`);
  params.push(query.warehouse.trim().toUpperCase());
  paramIdx++;
}
if (query.container_no) {
  conditions.push(`(o.container_no ILIKE $${paramIdx} OR o.id IN (SELECT dd2.parent_id FROM oms.orders dd2 WHERE dd2.container_no ILIKE $${paramIdx} AND dd2.doc_type = 'DD') OR o.sap_doc_num IN (SELECT DISTINCT ddl2.source_doc_number FROM oms.order_lines ddl2 JOIN oms.orders dd3 ON ddl2.order_id = dd3.id WHERE dd3.container_no ILIKE $${paramIdx} AND dd3.doc_type = 'DD'))`);
  params.push('%' + query.container_no.trim() + '%');
  paramIdx++;
}
if (query.oms_status) {
  const omsStatuses = query.oms_status.split(',').map(s => s.trim()).filter(Boolean);
  if (omsStatuses.length === 1) {
    conditions.push(`o.oms_status = $${paramIdx++}`);
    params.push(omsStatuses[0]);
  } else if (omsStatuses.length > 1) {
    conditions.push(`o.oms_status = ANY($${paramIdx++}::text[])`);
    params.push(omsStatuses);
  }
}
if (query.date_from) {
  conditions.push(`o.doc_date >= $${paramIdx++}`);
  params.push(query.date_from);
}
if (query.date_to) {
  conditions.push(`o.doc_date <= $${paramIdx++}`);
  params.push(query.date_to);
}

// SAP 显示状态过滤 (open/planned/released/closed/cancelled)
if (query.sap_display_status) {
  const statuses = query.sap_display_status.split(',').map(s => s.trim()).filter(Boolean);
  const sapConds = [];
  statuses.forEach(s => {
    switch(s) {
      case 'open':
        sapConds.push("(o.sap_status = 'O' AND o.sap_cancelled = 'N')");
        break;
      case 'planned':
        sapConds.push("(o.sap_status = 'P')");
        break;
      case 'released':
        sapConds.push("(o.sap_status = 'R')");
        break;
      case 'closed':
        sapConds.push("(o.sap_status IN ('C','L') AND o.sap_cancelled = 'N')");
        break;
      case 'cancelled':
        sapConds.push("(o.sap_cancelled = 'Y')");
        break;
    }
  });
  if (sapConds.length > 0) {
    conditions.push('(' + sapConds.join(' OR ') + ')');
  }
}

const page = Math.max(1, parseInt(query.page) || 1);
const pageSize = Math.min(100, Math.max(1, parseInt(query.page_size) || 20));
const offset = (page - 1) * pageSize;

const whereClause = conditions.join(' AND ');

const countSql = `SELECT COUNT(*) AS total FROM oms.orders o WHERE ${whereClause}`;
const listSql = `SELECT o.id, o.doc_type, o.doc_number, o.sap_doc_entry, o.sap_doc_num,
  o.business_partner AS bp_code, o.bp_name, o.doc_date, o.due_date,
  o.sap_status, o.sap_cancelled, o.oms_status, o.execution_state,
  o.doc_total, o.doc_currency,
  CASE WHEN o.is_split THEN (SELECT STRING_AGG(DISTINCT dd_c.container_no, ', ' ORDER BY dd_c.container_no) FROM oms.orders dd_c WHERE dd_c.doc_type = 'DD' AND dd_c.container_no IS NOT NULL AND dd_c.container_no <> '' AND (dd_c.parent_id = o.id OR dd_c.id IN (SELECT DISTINCT ol_dd.order_id FROM oms.order_lines ol_dd WHERE ol_dd.source_doc_number = o.sap_doc_num))) ELSE o.container_no END AS container_no, o.is_split,
  o.parent_id, o.split_seq, o.wms_document_id, o.created_at,
  o.item_code, o.item_name,
  (SELECT CASE WHEN SUM(ol.quantity) > 0
    THEN SUM(COALESCE(ol.wms_actual_qty, 0)) / SUM(ol.quantity)
    ELSE 0 END
   FROM oms.order_lines ol WHERE ol.order_id = o.id) AS completion_rate,
  COALESCE(o.warehouse_code, (SELECT CASE WHEN COUNT(DISTINCT olw.warehouse_code) = 1 THEN MIN(olw.warehouse_code) ELSE NULL END FROM oms.order_lines olw WHERE olw.order_id = o.id)) AS warehouse_code,
  COALESCE(o.planned_qty, (SELECT COALESCE(SUM(ol2.quantity), 0) FROM oms.order_lines ol2 WHERE ol2.order_id = o.id)) AS total_planned_qty,
  CASE WHEN o.is_split THEN (SELECT COALESCE(SUM(ol2.picked_qty), 0) FROM oms.order_lines ol2 WHERE ol2.order_id = o.id) ELSE COALESCE(o.actual_qty, (SELECT COALESCE(SUM(ol2.wms_actual_qty), 0) FROM oms.order_lines ol2 WHERE ol2.order_id = o.id)) END AS total_actual_qty
FROM oms.orders o
WHERE ${whereClause}
ORDER BY o.doc_date DESC, o.id DESC
LIMIT ${pageSize} OFFSET ${offset}`;

return { json: {
  _error: false,
  countSql, listSql,
  params, page, pageSize
} };

// V1.0: 格式化查询结果
const countRow = $('Count Query').first().json;
const total = parseInt(countRow.total) || 0;
const orders = total > 0 ? $('List Query').all().map(r => r.json).filter(r => r.id) : [];
const queryParams = $('构建查询').first().json;

return { json: {
  success: true,
  orders: orders,
  total: total,
  page: queryParams.page,
  page_size: queryParams.pageSize
} };

// V2.0: 解析订单行查询参数
const query = $input.first().json.query || {};
const orderId = parseInt(query.order_id);
const companyCode = $env.DP_COMPANY_CODE;

if (!orderId || !companyCode) {
  return { json: { _error: true, message: 'Missing order ID or company code' } };
}

return { json: { _error: false, orderId, companyCode } };

// V3.0: 合并行项目和DD子单 (去重)
const lines = $('Query Lines').all().map(r => r.json);

// DD子单 (可能有重复，按 id 去重)
let ddChildren = [];
try {
  const seen = new Set();
  $('Query DD Children').all().forEach(r => {
    if (r.json.id && !seen.has(r.json.id)) {
      seen.add(r.json.id);
      ddChildren.push(r.json);
    }
  });
} catch(e) {
  // Query DD Children 未执行时安全忽略
}

return { json: {
  success: true,
  lines: lines,
  dd_children: ddChildren
} };

// V1.0: 解析批量订单行参数
const query = $input.first().json.query || {};
const companyCode = $env.DP_COMPANY_CODE;

if (!companyCode) {
  return { json: { _error: true, message: 'DP_COMPANY_CODE not set' } };
}

const orderIdsStr = query.order_ids || '';
if (!orderIdsStr) {
  return { json: { _error: true, message: 'Missing order_ids parameter' } };
}

const idsArray = orderIdsStr.split(',').map(s => s.trim()).filter(Boolean).map(Number).filter(n => !isNaN(n) && n > 0);
if (!Array.isArray(idsArray) || idsArray.length === 0) {
  return { json: { _error: true, message: 'Invalid order_ids' } };
}
if (idsArray.length > 50) {
  return { json: { _error: true, message: '批量查询上限 50 个订单' } };
}

return { json: { _error: false, idsArray, companyCode } };

// V2.0: 合并批量行和DD子单，按 order_id 分组 (支持多 SO 关联)
const lines = $('Batch Query Lines').all().map(r => r.json);
let ddChildren = [];
try {
  const seen = new Set();
  $('Batch Query DD Children').all().forEach(r => {
    if (r.json.id && !seen.has(r.json.id)) {
      seen.add(r.json.id);
      ddChildren.push(r.json);
    }
  });
} catch(e) {}

// 按 order_id 分组
const results = {};
const idsArray = $('解析批量参数').first().json.idsArray;
idsArray.forEach(id => { results[id] = { lines: [], dd_children: [] }; });

lines.forEach(ln => {
  if (results[ln.order_id]) results[ln.order_id].lines.push(ln);
});

// DD 子单按 related_order_ids 分配到所有关联 SO (支持跨 SO 的 DD)
ddChildren.forEach(dd => {
  const relatedIds = dd.related_order_ids || (dd.parent_id ? [dd.parent_id] : []);
  relatedIds.forEach(soId => {
    if (results[soId]) {
      // 防重复 (同一 DD 不重复加入同一 SO)
      if (!results[soId].dd_children.some(d => d.id === dd.id)) {
        results[soId].dd_children.push(dd);
      }
    }
  });
});

return { json: { success: true, results } };
